mapper.update:
UPDATE GiaVe
SET giaVe = #{giaVe},
    maTuyen = #{maTuyen},
    maMua = #{maMua},
    ngayBatDau = #{ngayBatDau},
    ngayKetThuc = #{ngayKetThuc}
WHERE maGiaVe = #{maGiaVe}
AND maMua = #{maMua}
AND maTuyen = #{maTuyen}

mapper.delete:
DELETE FROM GiaVe
WHERE maGiaVe = #{maGiaVe}
AND maMua = #{maMua}
AND maTuyen = #{maTuyen}

mapper.select:
        SELECT *
		FROM GiaVe
		WHERE maTuyen = #{maTuyen}
		  AND maMua = #{maMua}
		  AND ngayBatDau <= #{ngayGioKhoiHanh}
		  AND (ngayKetThuc IS NULL OR #{ngayGioKhoiHanh} <= ngayKetThuc)

        WITH RECURSIVE seat_numbers AS (
		    SELECT 1 AS gheNgoi
		    UNION ALL
		    SELECT gheNgoi + 1
		    FROM seat_numbers
		    WHERE gheNgoi < (
		        SELECT lx.soGhe
		        FROM Xe x
		        JOIN LoaiXe lx ON x.maLoaiXe = lx.maLoaiXe
		        WHERE x.maXe = 'X001'
		    )
		)
		SELECT s.gheNgoi
		FROM seat_numbers s
		LEFT JOIN Ve v
		       ON v.gheNgoi = s.gheNgoi
		      AND v.maXe = #{maXe}
		      AND v.maTuyen = #{maTuyen}
		      AND v.maChuyen = #{maChuyen}
		WHERE v.gheNgoi IS NOT NULL;
